DROP TABLE IF EXISTS `exam_settings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `exam_settings` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `exam_id` bigint(20) unsigned NOT NULL,
  `webcam_enabled` tinyint(1) NOT NULL DEFAULT 1,
  `browser_lock_enabled` tinyint(1) NOT NULL DEFAULT 1,
  `tab_switch_detection` tinyint(1) NOT NULL DEFAULT 1,
  `max_tab_switches` int(11) NOT NULL DEFAULT 3,
  `shuffle_questions` tinyint(1) NOT NULL DEFAULT 0,
  `shuffle_options` tinyint(1) NOT NULL DEFAULT 0,
  `show_correct_answers` tinyint(1) NOT NULL DEFAULT 0,
  `show_score` tinyint(1) NOT NULL DEFAULT 1,
  `max_attempts` int(11) DEFAULT NULL,
  `grade_method` enum('highest','latest','average') NOT NULL DEFAULT 'highest',
  `passing_score` int(11) NOT NULL DEFAULT 60,
  `snapshot_interval` int(11) NOT NULL DEFAULT 30,
  `block_keyboard_shortcuts` tinyint(1) NOT NULL DEFAULT 1,
  `auto_submit_threshold` int(11) NOT NULL DEFAULT 5,
  `lock_ip` tinyint(1) NOT NULL DEFAULT 1,
  `detect_devtools` tinyint(1) NOT NULL DEFAULT 1,
  `detect_vm` tinyint(1) NOT NULL DEFAULT 0,
  `prevent_screenshot` tinyint(1) NOT NULL DEFAULT 1,
  `strict_mode` tinyint(1) NOT NULL DEFAULT 0,
  `heartbeat_interval` int(10) unsigned NOT NULL DEFAULT 30,
  `max_suspicious_activities` int(10) unsigned NOT NULL DEFAULT 10,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `exam_settings_exam_id_unique` (`exam_id`),
  CONSTRAINT `exam_settings_exam_id_foreign` FOREIGN KEY (`exam_id`) REFERENCES `exams` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=372 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

